	@Test
	void physicalAlternativeReactivatesRuleThatReadsPhysicalExpressions() {
		List<DependencyObservation> observations = new ArrayList<>();
		RuleRegistry registry = RuleRegistry.builder()
				.add(new PhysicalExpressionConsumerRule(observations))
				.add(new PhysicalExpressionProducerRule())
				.build();

		new CascadesPlanner(CascadesCostModel.from(new EvaluationStatistics()), registry, CascadesTelemetry.NO_OP)
				.optimize(pattern(), OptimizationGoal.root());

		assertEquals(List.of(
				new DependencyObservation(0L, 0L, 0L, false),
				new DependencyObservation(0L, 1L, 0L, true)), observations,
				"The physical expression itself must wake the consumer before winner selection can mask the gap");
	}

	@Test
	void physicalAlternativeWakesConsumerWithoutRematchingLogicalOnlyCompiledRule() {
		AtomicInteger compiledMatchAttempts = new AtomicInteger();
		List<DependencyObservation> observations = new ArrayList<>();
		CascadesRule compiledLogicalRule = new MatchCountingRule(
				RuleCompiler.compile(StandardRuleSpecs.safeScopeChangeRemoval()), compiledMatchAttempts);
		RuleRegistry registry = RuleRegistry.builder()
				.add(compiledLogicalRule)
				.add(new LegacyPhysicalExpressionConsumerRule(observations))
				.add(new PhysicalExpressionProducerRule())
				.build();

		new CascadesPlanner(CascadesCostModel.from(new EvaluationStatistics()), registry, CascadesTelemetry.NO_OP)
				.optimize(pattern(), OptimizationGoal.root());

		assertEquals(1, compiledMatchAttempts.get(),
				"A physical memo addition must be filtered before a logical-only compiled rule converts shared IR");
		assertEquals(List.of(
				new DependencyObservation(0L, 0L, 0L, false),
				new DependencyObservation(0L, 1L, 0L, true)), observations,
				"Legacy default-all descriptors must observe the explicit sibling physical-frontier event once");
	}

