	@Test
	void queuedRuleWorkCoalescesRevisionsByExpressionIdentity() {
		int producedAlternatives = 24;
		AtomicInteger matchAttempts = new AtomicInteger();
		List<Long> observedPhysicalRevisions = new ArrayList<>();
		RuleRegistry.Builder registry = RuleRegistry.builder()
				.add(new CoalescedPhysicalRevisionConsumerRule(matchAttempts, observedPhysicalRevisions));
		for (int index = 0; index < producedAlternatives; index++) {
			registry.add(new DistinctPhysicalAlternativeProducerRule(index));
		}

		CascadesPlan plan = new CascadesPlanner(CascadesCostModel.from(new EvaluationStatistics()), registry.build(),
				CascadesTelemetry.NO_OP)
						.optimize(pattern(), OptimizationGoal.root());

		assertEquals(OptimizationCompleteness.COMPLETE, plan.completeness());
		assertEquals(List.of(0L, (long) producedAlternatives), observedPhysicalRevisions,
				"The coalesced task must execute against the latest group revision");
		assertEquals(2, matchAttempts.get(),
				"One expression may have only one pending transformation task while its revision advances");
	}

	@Test
	void expressionLocalEnforcerMatchesEachImmutableExpressionOnce() {
		int producedAlternatives = 24;
		Map<Integer, Integer> matchAttemptsByExpression = new LinkedHashMap<>();
		CascadesRule materializeEnforcer = new ExpressionMatchCountingRule(
				RuleCompiler.compile(StandardRuleSpecs.materializeEnforcer()), matchAttemptsByExpression);
		RuleRegistry.Builder registry = RuleRegistry.builder().add(materializeEnforcer);
		for (int index = 0; index < producedAlternatives; index++) {
			registry.add(new DistinctPhysicalAlternativeProducerRule(index));
		}
		OptimizationGoal materializedGoal = OptimizationGoal.exact(PhysicalProperties.builder()
				.materialization(PhysicalProperties.Materialization.MATERIALIZED)
				.build());

		CascadesPlan plan = new CascadesPlanner(CascadesCostModel.from(new EvaluationStatistics()), registry.build(),
				CascadesTelemetry.NO_OP)
						.optimize(pattern(), materializedGoal);

		int expressionCount = plan.memo()
				.groups()
				.stream()
				.mapToInt(group -> group.expressions().size())
				.sum();
		assertEquals(OptimizationCompleteness.COMPLETE, plan.completeness(), plan.diagnostics().toString());
		assertEquals(expressionCount, matchAttemptsByExpression.size(),
				"Every immutable expression must receive the expression-local enforcer");
		assertEquals(expressionCount,
				matchAttemptsByExpression.values().stream().mapToInt(Integer::intValue).sum(),
				() -> "Adding a physical sibling must not rematch old immutable expressions: "
						+ matchAttemptsByExpression);
	}

